import functools


class Solution:
    def stoneGameIX(self, stones):
        c0 = c1 = c2 = 0
        for s in stones:
            r = s % 3
            if r == 0:
                c0 += 1
            elif r == 1:
                c1 += 1
            else:
                c2 += 1

        @functools.lru_cache(maxsize=None)
        def solve(a, b, c, total_mod, alice_turn):
            if a + b + c == 0:
                return False
            counts = [a, b, c]
            outcomes = []
            for r in range(3):
                if counts[r] > 0:
                    nc = list(counts)
                    nc[r] -= 1
                    new_mod = (total_mod + r) % 3
                    if new_mod == 0:
                        outcome = not alice_turn
                    else:
                        outcome = solve(nc[0], nc[1], nc[2], new_mod, not alice_turn)
                    outcomes.append(outcome)
            if alice_turn:
                return any(outcomes)
            return all(outcomes)

        return solve(c0, c1, c2, 0, True)

