class Solution:
    def stoneGameIX(self, stones):
        cnt = [0, 0, 0]
        for s in stones:
            cnt[s % 3] += 1
        if cnt[0] % 2 == 0:
            return cnt[1] >= 1 and cnt[2] >= 1
        return abs(cnt[1] - cnt[2]) > 2

